#include<bits/stdc++.h>
using namespace std;
int T,t,num[13]={0,1,6,11,15,19,22,25,27,29,30,30,31};
int main(void){
	scanf("%d",&T);
	while(T--){
		scanf("%d",&t);
		int day=t/720,h=t%720/60,a=h/10,b=h%10,c,d; 
		long long ans=day*num[12]+num[h];
		if(h==0)a=1,b=2;
		for(int i=0;i<=t%60;++i){
			c=i/10,d=i%10;
			if((!a&&b-c==c-d)||(a&&a-b==b-c&&b-c==c-d))++ans;
		}printf("%d\n",ans);
	}
	return false;
}
